// // This module selects between ALU output and memory data based on the MemToReg control signal. If MemToReg is low (0), the output will be MemoryData; if high (1), the output will be AluData.
module top_module(AluData, MemoryData, MemToReg, Halt, WriteData);input [15:0] AluData, MemoryData;
   input 	MemToReg;
   input 	Halt;   

   output 	[15:0] WriteData;

   assign WriteData = MemToReg ? MemoryData : AluData;
endmodule
